<h3>Scala 3 (inline + compiletime + Mirror)</h3>
<pre><code class="language-scala">// Tuples.Combiner — Scala 3
object Combiner {
  type WithOut[A, B, O] = Combiner[A, B] { type Out = O }

  // Compile-time type-level flattening
  type Flatten[T] &lt;: Tuple = T match {
    case EmptyTuple =&gt; EmptyTuple
    case h *: t     =&gt; h match {
      case Tuple =&gt; Tuple.Concat[Flatten[h], Flatten[t]]
      case _     =&gt; h *: Flatten[t]
    }
    case _          =&gt; T *: EmptyTuple
  }

  type Combined[A, B] = Flatten[A *: B *: EmptyTuple]

  inline given [A, B]: Combiner[A, B] =
    // Use scala.compiletime.erasedValue, constValueTuple, summonInline
    // to generate flattening logic at compile time.
    //
    // 1. Convert A to tuple representation (identity if already tuple, else wrap)
    // 2. Convert B to tuple representation
    // 3. Concatenate
    // 4. Flatten recursively
