object Separator {
  type WithOut[A, L, R] = Separator[A] { type Left = L; type Right = R }

  type Init[T &lt;: Tuple] &lt;: Tuple = T match {
    case x *: EmptyTuple =&gt; EmptyTuple
    case x *: xs         =&gt; x *: Init[xs]
  }

  type Last[T &lt;: Tuple] = T match {
    case x *: EmptyTuple =&gt; x
    case x *: xs         =&gt; Last[xs]
  }

  inline given [A]: Separator[A] =
    // 1. Flatten A into canonical flat tuple (reuse Combiner.Flatten)
    // 2. Left = Init[Flattened] (all but last)
