}

// Eithers.Combiner — Scala 3
object EitherCombinerMacros {
  // Type-level left-nesting
  type LeftNest[L, R] = R match {
    case Either[x, y] =&gt; LeftNest[Either[L, x], y]
    case _            =&gt; Either[L, R]
  }

  inline given [L, R]: Eithers.Combiner[L, R] =
