object EitherSeparatorMacros {
  // Type-level extraction of rightmost non-Either type
  type RightmostOf[A] = A match {
    case Either[l, r] =&gt; r match {
      case Either[_, _] =&gt; RightmostOf[LeftNest[l, r]]
      case _            =&gt; r
    }
  }

  type AllButRightmost[A] = A match {
    case Either[l, r] =&gt; r match {
      case Either[_, _] =&gt; AllButRightmost[LeftNest[l, r]]
      case _            =&gt; l
