<h2>Test Suites</h2>
<h3>Tuples Tests</h3>
<pre><code class="language-scala">class TuplesSpec extends AnyFlatSpec with Matchers {

  val tuples: Tuples = ??? // production instance

  // --- Combiner ---

  "Tuples.combine" should "combine two atomic values into a pair" in {
    tuples.combine(1, "a") shouldBe (1, "a")
  }

  it should "append an atomic value to a tuple" in {
    tuples.combine((1, "a"), true) shouldBe (1, "a", true)
  }

  it should "prepend an atomic value to a tuple" in {
    tuples.combine(1, ("a", true)) shouldBe (1, "a", true)
  }

  it should "flatten two tuples" in {
    tuples.combine((1, "a"), (true, 3.0)) shouldBe (1, "a", true, 3.0)
  }

  it should "flatten deeply nested tuples" in {
    tuples.combine(((1, "a"), true), (3.0, ('x', "y"))) shouldBe (1, "a", true, 3.0, 'x', "y")
  }

  // --- Separator ---

  "Tuples.separate" should "separate a pair into left and right" in {
    tuples.separate((1, "a")) shouldBe (1, "a")
  }

  it should "peel the rightmost element from a triple" in {
    tuples.separate((1, "a", true)) shouldBe ((1, "a"), true)
  }

  it should "peel the rightmost element from a 4-tuple" in {
    tuples.separate((1, "a", true, 3.0)) shouldBe ((1, "a", true), 3.0)
  }

  it should "canonicalize non-flat input before separating" in {
    tuples.separate(((1, "a"), (true, 3.0))) shouldBe ((1, "a", true), 3.0)
  }

  // --- Round-trip (simple case) ---

  "Tuples round-trip" should "recover right element after combine then separate" in {
    val combined = tuples.combine((1, "a"), true)
    val (left, right) = tuples.separate(combined)
    right shouldBe true
    left shouldBe (1, "a")
  }

  // --- Recursive peeling ---

  "Tuples recursive peeling" should "fully decompose a tuple" in {
    val t = (1, "a", true, 3.0)

    val (rest1, d) = tuples.separate(t)
    d shouldBe 3.0

    val (rest2, c) = tuples.separate(rest1)
    c shouldBe true

    val (a, b) = tuples.separate(rest2)
    a shouldBe 1
    b shouldBe "a"
  }
}
</code></pre>
<h3>Eithers Tests</h3>
<pre><code class="language-scala">class EithersSpec extends AnyFlatSpec with Matchers {

  val eithers: Eithers = ??? // production instance

  // --- Combiner ---

  "Eithers.combine" should "pass through an already-atomic Either" in {
    eithers.combine(Left(1): Either[Int, String]) shouldBe Left(1)
    eithers.combine(Right("a"): Either[Int, String]) shouldBe Right("a")
  }

  it should "reassociate a right-nested Either to left-nested form" in {
    // Either[Int, Either[String, Boolean]] → Either[Either[Int, String], Boolean]
    val input: Either[Int, Either[String, Boolean]] = Right(Right(true))
    val result = eithers.combine(input)
    result shouldBe Right(true)

    val input2: Either[Int, Either[String, Boolean]] = Right(Left("a"))
    val result2 = eithers.combine(input2)
    result2 shouldBe Left(Right("a"))

    val input3: Either[Int, Either[String, Boolean]] = Left(1)
    val result3 = eithers.combine(input3)
    result3 shouldBe Left(Left(1))
  }

  it should "reassociate deeply right-nested Eithers" in {
    // Either[A, Either[B, Either[C, D]]] → Either[Either[Either[A, B], C], D]
    val input: Either[Int, Either[String, Either[Boolean, Double]]] =
      Right(Right(Right(3.0)))
    val result = eithers.combine(input)
    result shouldBe Right(3.0)
  }

  // --- Separator ---

  "Eithers.separate" should "separate a simple Either" in {
    val result = eithers.separate(Left(1): Either[Int, String])
    result shouldBe Left(1)

    val result2 = eithers.separate(Right("a"): Either[Int, String])
    result2 shouldBe Right("a")
  }

  it should "peel the rightmost alternative from a left-nested Either" in {
    // Either[Either[Int, String], Boolean] → Left = Either[Int, String], Right = Boolean
    val input: Either[Either[Int, String], Boolean] = Right(true)
    val result = eithers.separate(input)
    result shouldBe Right(true)

    val input2: Either[Either[Int, String], Boolean] = Left(Left(1))
    val result2 = eithers.separate(input2)
    result2 shouldBe Left(Left(1))
  }

  it should "canonicalize right-nested input before separating" in {
    // Either[Int, Either[String, Boolean]] → canonicalize → separate
    val input: Either[Int, Either[String, Boolean]] = Right(Right(true))
    val result = eithers.separate(input)
    result shouldBe Right(true)
  }

  // --- Recursive peeling ---

  "Eithers recursive peeling" should "fully decompose a nested Either" in {
    val input: Either[Either[Either[Int, String], Boolean], Double] = Right(3.0)

    val step1 = eithers.separate(input)
    step1 shouldBe Right(3.0)

    // Simulate Left case traversal
    val input2: Either[Either[Either[Int, String], Boolean], Double] =
      Left(Right(true))
    val step2a = eithers.separate(input2)
    step2a shouldBe Left(Right(true)) // Left is Either[Either[Int, String], Boolean]

    // Peel again from the left
    val step2b = eithers.separate(Left(Right(true)): Either[Either[Int, String], Boolean])
    step2b shouldBe Right(true)
  }
}
</code></pre>
<h3>Unions Tests (Scala 3 only)</h3>
<pre><code class="language-scala">class UnionsSpec extends AnyFlatSpec with Matchers {

  val unions: Unions = ??? // production instance

  // --- Combiner ---

  "Unions.combine" should "inject a left value into a union" in {
    val result: Int | String = unions.combine(Left(1): Either[Int, String])
    result shouldBe 1
  }

  it should "inject a right value into a union" in {
    val result: Int | String = unions.combine(Right("a"): Either[Int, String])
    result shouldBe "a"
  }

  it should "inject into a wider union from compound left" in {
    val result: Int | String | Boolean =
      unions.combine(Right(true): Either[Int | String, Boolean])
    result shouldBe true
  }

  // --- Separator ---

  "Unions.separate" should "discriminate the rightmost member" in {
    val v: Int | String | Boolean = true
    val result = unions.separate(v)
    result shouldBe Right(true)
  }

  it should "return Left for non-rightmost members" in {
    val v: Int | String | Boolean = 42
    val result = unions.separate(v)
    result shouldBe Left(42) // 42 is in Int | String (the left union)
  }

  it should "handle string in a three-member union" in {
    val v: Int | String | Boolean = "hello"
    val result = unions.separate(v)
    result shouldBe Left("hello") // "hello" is in Int | String
  }

  // --- Recursive peeling ---

  "Unions recursive peeling" should "fully decompose a union" in {
    val v: Int | String | Boolean = "hello"

    val step1 = unions.separate(v)
    // Right = Boolean, Left = Int | String
    step1 shouldBe Left("hello")

    step1 match {
      case Left(remaining) =&gt;
        val step2 = unions.separate(remaining)
        // Right = String, Left = Int
        step2 shouldBe Right("hello")
      case Right(_) =&gt;
        fail("Expected Left")
    }
  }

  // --- Round-trip: union → either → union ---

  "Unions round-trip" should "survive combine then separate" in {
    val original = 42
    val combined: Int | String = unions.combine(Left(original): Either[Int, String])
    val separated = unions.separate(combined)
    separated shouldBe Left(42)
  }

  // --- Edge case: erased types ---

  "Unions.separate" should "handle distinct concrete types reliably" in {
    val v: Int | String | Double = 3.14
    val result = unions.separate(v)
    result shouldBe Right(3.14)
  }

  // NOTE: Unions with overlapping erased types (e.g., List[Int] | List[String])
  // are inherently unsafe and should produce compile-time warnings via TypeTest.
}
</code></pre>
<h3>Law / Property Tests</h3>
<pre><code class="language-scala">class AlgebraicLawsSpec extends AnyFlatSpec with Matchers {

  val tuples: Tuples   = ???
  val eithers: Eithers = ???
  val unions: Unions    = ???

  // --- Canonicalization idempotence ---

  "Tuples canonicalization" should "be idempotent" in {
    // Combining then separating a canonical tuple and re-combining
    // should yield the same canonical tuple.
    val canonical = (1, "a", true, 3.0)
    val (left, right) = tuples.separate(canonical)
    val recombined = tuples.combine(left, right)
    recombined shouldBe canonical
  }

  "Eithers canonicalization" should "be idempotent" in {
    // Separating a canonical left-nested Either and re-combining
    // should yield the same structure.
    val canonical: Either[Either[Int, String], Boolean] = Left(Right("a"))
    val separated = eithers.separate(canonical)
    val recombined = eithers.combine(separated)
    recombined shouldBe canonical
  }

  // --- Separator always produces atomic Right ---

  "Tuples.separate right" should "never be a tuple" in {
    val (_, right) = tuples.separate((1, "a", true))
    right shouldBe a[Boolean] // atomic, not a tuple
  }

  "Eithers.separate right" should "never be an Either" in {
    val result = eithers.separate(
      Left(Left(1)): Either[Either[Int, String], Boolean]
    )
    result match {
      case Right(v) =&gt; v should not be an[Either[_, _]]
      case Left(_)  =&gt; // left is fine
    }
  }

  // --- Combine then separate recovers the right operand ---

  "Tuples" should "recover right operand after combine+separate (atomic right)" in {
    val combined = tuples.combine((1, "a"), true)
    val (_, right) = tuples.separate(combined)
    right shouldBe true
  }

  "Eithers" should "recover right alternative after combine+separate" in {
    val combined = eithers.combine(Right(true): Either[Either[Int, String], Boolean])
    val separated = eithers.separate(combined)
    separated shouldBe Right(true)
  }
}
</code></pre>
<hr>
<h2>Design Decisions and Open Questions</h2>
<h3>Why <code>sealed trait</code> for the top-level types?</h3>
<p><code>Tuples</code>, <code>Eithers</code>, and <code>Unions</code> are sealed traits to allow controlled extension (e.g., a production implementation provided by a companion <code>object</code> or a test mock), while preventing arbitrary subclassing.</p>
<h3>Why <code>Either[L, R]</code> as input to <code>Eithers.Combiner</code> and <code>Unions.Combiner</code>?</h3>
<p>Because constructing a sum requires knowing <em>which branch</em> you're injecting. Two separate <code>left</code>/<code>right</code> methods would require the caller to specify both type parameters, but only one can be inferred from the value argument. Accepting <code>Either[L, R]</code> lets both type parameters be inferred from a single argument.</p>
<h3>Why does <code>Unions.Separator</code> return <code>Either</code> and not a union?</h3>
<p>Because separating is fundamentally about discriminating. A union <code>A | B | C</code> at runtime is just a value — you can't pattern match on union membership without type tests. Separator bridges the untagged world to the tagged world, giving you an <code>Either[A | B, C]</code> that you can match on safely.</p>
<h3>Erased type safety for Unions</h3>
<p>Union separation relies on runtime type discrimination. This is safe for distinct concrete types (<code>Int | String | Boolean</code>) but unsound for types that erase identically (<code>List[Int] | List[String]</code>). Macro-generated instances should require <code>TypeTest</code> evidence and produce compile-time warnings when discrimination is unsafe.</p>
<h3>Non-invertibility of combine/separate</h3>
<p><code>combine</code> followed by <code>separate</code> recovers the right operand <strong>only when the right operand is atomic</strong> (not itself a compound type of the same family). When the right operand is compound, it gets absorbed into the canonical form and the original grouping is lost. This is by design — canonicalization is more valuable than preserving arbitrary groupings.</p></body></html>

# Memoizing Scala Macro Expansions

## Why the Compiler Cannot Help

The Scala compiler does not cache or deduplicate macro expansions. Sébastien Doeraene (Scala 3 core developer) confirmed on Scala Contributors (August 2025) that this is by design: macros are arbitrary functions, so the compiler cannot determine whether they are pure or what constitutes "same inputs." The set of information available to a macro is too large for the compiler to reason about equality of invocations.

> **Source:** [[Does the compiler recognize and optimize the same macro expansions?](https://contributors.scala-lang.org/t/does-the-compiler-recognize-and-optimize-the-same-macro-expansions/7187)](https://contributors.scala-lang.org/t/does-the-compiler-recognize-and-optimize-the-same-macro-expansions/7187) — Sébastien Doeraene (sjrd), August 2025.

The `scalac-profiling` plugin (Scala 2) tracks an "optimistic counter" showing how many expansions returned identical stringified ASTs, confirming the problem is real and measurable — but the compiler still does not cache them.

> **Source:** [[Speeding Up Compilation Time with scalac-profiling](https://www.scala-lang.org/blog/2018/06/04/scalac-profiling.html)](https://www.scala-lang.org/blog/2018/06/04/scalac-profiling.html) — Jorge Vicente Cantero, Scala Center, 2018.

Any caching must therefore be implemented **within the macro implementation itself**.

## The Core Technique: Static Mutable State

Macro implementations are pre-compiled JVM classes loaded by the compiler. Object-level (`static`) fields on these classes persist across all invocations within a single compiler run. This makes them a natural location for a cache.

> **Source:** Eugene Burmako's original guidance on macro caching via mutable state keyed on `c.currentRun`: [[scala-user mailing list, 2012](https://groups.google.com/g/scala-user/c/32SDp5oLIJ4)](https://groups.google.com/g/scala-user/c/32SDp5oLIJ4).

### What to Cache

**Critical constraint:** In both Scala 2 and Scala 3, AST nodes (`Tree`, `Expr`, `Term`) are tied to a specific compiler context. In Scala 2 they are path-dependent on `c.universe`; in Scala 3 they are path-dependent on the `Quotes` instance. These values **cannot be reused across different `Quotes` contexts**.

The correct approach is to cache **intermediate analysis results** — the expensive computation that produces plain Scala data — and then cheaply reconstruct the final `Expr` or `Tree` from cached data on each invocation.

### Scala 2 Pattern

In Scala 2, use a `java.util.WeakHashMap` keyed on `c.currentRun` to scope the cache to a single compilation run. This prevents memory leaks in long-lived JVMs (IDEs, sbt with `~ compile`), because the `Run` object is garbage-collected when the compilation finishes.

```scala
import scala.reflect.macros.blackbox.Context
import java.util.WeakHashMap

object TypeIdMacros {
  // Intermediate analysis result — plain Scala data, not compiler-specific
  private case class TypeIdData(fullName: String, fields: List[(String, String)])

  // WeakHashMap keyed on compiler Run; GC'd when run ends
  private val cache = new WeakHashMap[Any, scala.collection.mutable.Map[String, TypeIdData]]()

  private def getRunCache(c: Context): scala.collection.mutable.Map[String, TypeIdData] = {
    val run = c.currentRun
    cache.synchronized {
      if (!cache.containsKey(run))
        cache.put(run, scala.collection.mutable.HashMap[String, TypeIdData]())
      cache.get(run)
    }
  }

  def typeIdImpl[T: c.WeakTypeTag](c: Context): c.Expr[TypeId] = {
    import c.universe._
    val tpe = c.weakTypeOf[T]
    val key = tpe.dealias.toString  // canonical string representation as cache key
    val runCache = getRunCache(c)

    val data = runCache.getOrElseUpdate(key, analyzeType(c)(tpe))  // expensive, only runs once
    buildExpr(c)(data)  // cheap reconstruction
  }

  private def analyzeType(c: Context)(tpe: c.universe.Type): TypeIdData = {
    // ... expensive type analysis ...
    ???
  }

  private def buildExpr(c: Context)(data: TypeIdData): c.Expr[TypeId] = {
    import c.universe._
    // Use quasiquotes to reconstruct the expression from plain data
    c.Expr[TypeId](q"TypeId(${data.fullName}, ${data.fields.map(f => q"(${f._1}, ${f._2})")})")
  }
}
```

In Scala 2, `Liftable[T]` is the type class that enables lifting plain values into quasiquotes. Built-in instances exist for primitive types, strings, options, and tuples. Custom instances can be defined for any data type:

```scala
import c.universe._
implicit val liftPoint: Liftable[Point] = Liftable[Point] { p =>
  q"_root_.mypackage.Point(${p.x}, ${p.y})"
}
```

> **Source:** [[Quasiquotes — Lifting](https://docs.scala-lang.org/overviews/quasiquotes/lifting.html)](https://docs.scala-lang.org/overviews/quasiquotes/lifting.html) — Scala Documentation.

Due to the path-dependent nature of the Scala 2 reflection API, each universe has its own `Liftable`. In practice, define the `Liftable` instance locally within the macro bundle or implementation method where `c.universe._` is imported.

### Scala 3 Pattern

In Scala 3, there is no `c.currentRun`. However, the classloader for macro implementations is discarded between compilations, so a simple `ConcurrentHashMap` on the macro object naturally scopes to a single compilation lifecycle.

```scala
import scala.quoted.*
import java.util.concurrent.ConcurrentHashMap

object TypeIdMacros {
  // Intermediate analysis result — plain Scala data
  private case class TypeIdData(fullName: String, fields: List[(String, String)])

  // Cache persists for the duration of a single compilation
  private val cache = new ConcurrentHashMap[String, TypeIdData]()

  inline def typeId[T]: TypeId = ${ typeIdImpl[T] }

  def typeIdImpl[T: Type](using Quotes): Expr[TypeId] = {
    import quotes.reflect.*
    val tpe = TypeRepr.of[T].dealias
    val key = tpe.show  // canonical string representation as cache key

    val data = cache.computeIfAbsent(key, _ => analyzeType[T])  // expensive, only runs once
    dataToExpr(data)  // cheap reconstruction
  }

  private def analyzeType[T: Type](using Quotes): TypeIdData = {
    // ... expensive type analysis ...
    ???
  }

  private def dataToExpr(data: TypeIdData)(using Quotes): Expr[TypeId] = {
    // Reconstruct Expr from cached plain data using ToExpr / Expr.apply
    val nameExpr = Expr(data.fullName)
    val fieldsExpr = Expr.ofList(
      data.fields.map { (n, t) => '{ (${Expr(n)}, ${Expr(t)}) } }
    )
    '{ TypeId($nameExpr, $fieldsExpr) }
  }
}
```

## Reconstructing Expressions from Cached Data

The key to making caching work is efficient reconstruction: given a plain Scala value computed once and cached, build a fresh `Expr` cheaply on every subsequent invocation.

### Scala 3: `ToExpr` Type Class

`Expr.apply[T](value)(using Quotes, ToExpr[T])` converts a compile-time value into an expression representing that value at runtime. This is powered by the `ToExpr` type class:

```scala
trait ToExpr[T]:
  def apply(x: T)(using Quotes): Expr[T]
```

Built-in `ToExpr` instances exist for `Boolean`, `Int`, `Long`, `Float`, `Double`, `Char`, `String`, `BigInt`, `BigDecimal`, `Class`, all tuple arities, `Option`, `Either`, `Array`, `Seq`, `Set`, `List`, `Map`, and `StringContext`.

> **Source:** [[Macros — Scala 3 Reference](https://docs.scala-lang.org/scala3/reference/metaprogramming/macros.html)](https://docs.scala-lang.org/scala3/reference/metaprogramming/macros.html) — Scala Documentation.

For custom data types, implement `ToExpr` as a `given`:

```scala
case class TypeIdData(fullName: String, fields: List[(String, String)])

given ToExpr[TypeIdData] with
  def apply(data: TypeIdData)(using Quotes): Expr[TypeIdData] =
    '{ TypeIdData(${Expr(data.fullName)}, ${Expr(data.fields)}) }
```

This works because `String`, `List`, and `Tuple2[String, String]` all have built-in `ToExpr` instances, and `ToExpr` composes. Once defined, you can simply write `Expr(cachedData)` to reconstruct the expression.

> **Source:** [[Macros — Scala 3 EPFL](https://dotty.epfl.ch/docs/reference/metaprogramming/macros.html)](https://dotty.epfl.ch/docs/reference/metaprogramming/macros.html) — dotty documentation.

For more complex cases, use quoted patterns directly:

```scala
// Option[T] — a standard example from the Scala 3 documentation
given OptionToExpr[T: Type: ToExpr]: ToExpr[Option[T]] with
  def apply(opt: Option[T])(using Quotes): Expr[Option[T]] =
    opt match
      case Some(x) => '{ Some[T](${Expr(x)}) }
      case None    => '{ None }
```

Utility methods for building expressions from collections are also available:

- `Expr.ofList[T](xs: List[Expr[T]]): Expr[List[T]]` — constructs a list expression from a list of expressions.
- `Expr.ofSeq[T](xs: Seq[Expr[T]]): Expr[Seq[T]]` — likewise for sequences.
- `Expr.ofTupleFromSeq(xs: Seq[Expr[Any]]): Expr[Tuple]` — constructs a tuple from a sequence.
- `Varargs[T](xs: Seq[Expr[T]]): Expr[Seq[T]]` — for splicing as varargs.

> **Source:** [[Quoted Code — Scala 3 Macro Tutorial](https://lampepfl.github.io/scala3-macro-tutorial/docs/tutorial/quoted-code.html)](https://lampepfl.github.io/scala3-macro-tutorial/docs/tutorial/quoted-code.html).

### Scala 3: Direct AST Construction

If the target type is not something you control (i.e., you cannot define `ToExpr` for it), you can construct the expression using the TASTy Reflection API:

```scala
private def dataToExpr(data: TypeIdData)(using Quotes): Expr[TypeId] =
  import quotes.reflect.*
  // Equivalent to: TypeId("com.example.Foo", List(("name", "String")))
  val nameExpr = Expr(data.fullName)
  val fieldsExpr = Expr.ofList(
    data.fields.map { (n, t) => '{ (${Expr(n)}, ${Expr(t)}) } }
  )
  '{ TypeId($nameExpr, $fieldsExpr) }
```

You can also drop to the lower-level `Term` API via `.asTerm` and `.asExprOf[T]`, but quoted patterns are preferred for safety.

> **Source:** [[Reflection — Macros in Scala 3](https://docs.scala-lang.org/scala3/guides/macros/reflection.html)](https://docs.scala-lang.org/scala3/guides/macros/reflection.html) — Scala Documentation.

### Scala 2: `Liftable` and Quasiquotes

In Scala 2, `Liftable[T]` is the equivalent of Scala 3's `ToExpr[T]`. It maps a value of type `T` to a `Tree`. Built-in instances cover primitives, strings, and standard collections.

```scala
// Custom Liftable inside a macro implementation
import c.universe._

implicit val liftTypeIdData: Liftable[TypeIdData] = Liftable[TypeIdData] { data =>
  q"TypeIdData(${data.fullName}, ${data.fields})"
}
```

Because `Liftable` is path-dependent on the universe, it must be defined in a scope where `c.universe._` is imported. The recommended pattern is to define it inside a macro bundle or at the top of the implementation method.

> **Source:** [[Quasiquotes — Lifting](https://docs.scala-lang.org/overviews/quasiquotes/lifting.html)](https://docs.scala-lang.org/overviews/quasiquotes/lifting.html) — Scala Documentation.

## Cache Key Design

Use a canonical string representation of the type as the cache key:

- **Scala 2:** `tpe.dealias.toString` — calls `dealias` to resolve type aliases before stringifying.
- **Scala 3:** `TypeRepr.of[T].dealias.show` — `dealias` resolves aliases, `show` produces a canonical string.

Do **not** use `TypeRepr` or `c.universe.Type` objects directly as cache keys, because they are tied to a specific compiler context and may not behave correctly with standard hash maps across invocations.

> **Source:** [[Scala 3 macros tips & tricks](https://softwaremill.com/scala-3-macros-tips-and-tricks/)](https://softwaremill.com/scala-3-macros-tips-and-tricks/) — SoftwareMill Blog. Discusses `dealias`, `widen`, and `simplified` for obtaining canonical type representations.

## Profiling Before Optimizing

Before implementing caching, profile to confirm that macro expansion (rather than, say, implicit search triggered by the macro) is the actual bottleneck.

**Scala 2:** Use the `scalac-profiling` compiler plugin with `-Vstatistics` (2.13) or `-Ystatistics` (2.12) and `-P:scalac-profiling:show-profiles`. This reports per-macro invocation counts, time spent, AST nodes generated, and the count of repeated expansions.

> **Source:** [[scalac-profiling GitHub repository](https://github.com/scalacenter/scalac-profiling)](https://github.com/scalacenter/scalac-profiling) — Scala Center.

**Scala 3 (3.6.3+):** Use `-Yprofile-enabled -Yprofile-trace:path/to/compiler.trace` to generate trace events in a standard JSON format viewable in [[Perfetto UI](https://ui.perfetto.dev/)](https://ui.perfetto.dev).

> **Source:** [[Scala 3.6.3 release notes](https://www.scala-lang.org/news/3.6.3/)](https://www.scala-lang.org/news/3.6.3/) — Scala Language Blog, December 2024.

## Summary

1. Profile first to confirm macro expansion is the bottleneck.
2. Cache **computed data** (plain case classes, strings, lists), not `Expr`/`Tree`/`Term` values.
3. Use a `ConcurrentHashMap` (Scala 3) or a `WeakHashMap` keyed on `c.currentRun` (Scala 2) as the static cache on the macro implementation object.
4. Reconstruct fresh `Expr` values cheaply from cached data using `ToExpr` / `Expr.apply` (Scala 3) or `Liftable` / quasiquotes (Scala 2).
5. Use `TypeRepr.of[T].dealias.show` (Scala 3) or `tpe.dealias.toString` (Scala 2) as the canonical cache key.

