package zio.blocks.chunk

import java.nio.charset.Charset

import scala.annotation.{nowarn, tailrec}
import scala.collection.immutable.{IndexedSeq, LinearSeq}
import scala.collection.mutable
import scala.collection.mutable.Builder
import scala.math.log
import scala.reflect.ClassTag
import scala.util.hashing.MurmurHash3
import scala.util.{Failure, Success, Try}

/**
 * A `Chunk[A]` represents a chunk of values of type `A`. Chunks are usually
 * backed by arrays, but expose a purely functional, safe interface to the
 * underlying elements, and they become lazy on operations that would be costly
 * with arrays, such as repeated concatenation.
 * The implementation of balanced concatenation is based on the one for
 * Conc-Trees in "Conc-Trees for Functional and Parallel Programming" by
 * Aleksandar Prokopec and Martin Odersky.
 * [[http://aleksandar-prokopec.com/resources/docs/lcpc-conc-trees.pdf]]
 * NOTE: For performance reasons `Chunk` does not box primitive types. As a
 * result, it is not safe to construct chunks from heterogeneous primitive
 * types.
 */
sealed trait Chunk[+A] extends IndexedSeq[A] with Serializable { self =>
  import Chunk._

  def length: Int

  def apply(index: Int): A

  def chunkIterator: ChunkIterator[A]

  override def iterator: Iterator[A] = chunkIterator

  /**
   * Returns the concatenation of this chunk with the specified chunk.
   */
  final def ++[A1 >: A](that: Chunk[A1]): Chunk[A1] =
    (self, that) match {
      case (Chunk.AppendN(start, buffer, bufferUsed, _), that) =>
        val chunk = Chunk.fromArray(buffer.asInstanceOf[Array[A1]]).take(bufferUsed)
        start ++ chunk ++ that
      case (self, Chunk.PrependN(end, buffer, bufferUsed, _)) =>
        val chunk = Chunk.fromArray(buffer.asInstanceOf[Array[A1]]).takeRight(bufferUsed)
        self ++ chunk ++ end
      case (self, Chunk.Empty) => self
      case (Chunk.Empty, that) => that
      case (self, that) =>
        val diff = that.concatDepth - self.concatDepth
        if (math.abs(diff) <= 1) Chunk.Concat(self, that)
        else if (diff < -1) {
          if (self.left.concatDepth >= self.right.concatDepth) {
            val nr = self.right ++ that
            Chunk.Concat(self.left, nr)
          } else {
            val nrr = self.right.right ++ that
            if (nrr.concatDepth == self.concatDepth - 3) {
              val nr = Chunk.Concat(self.right.left, nrr)
              Chunk.Concat(self.left, nr)
            } else {
              val nl = Chunk.Concat(self.left, self.right.left)
              Chunk.Concat(nl, nrr)
            }
          }
        } else {
          if (that.right.concatDepth >= that.left.concatDepth) {
            val nl = self ++ that.left
            Chunk.Concat(nl, that.right)
          } else {
            val nll = self ++ that.left.left
            if (nll.concatDepth == that.concatDepth - 3) {
              val nl = Chunk.Concat(nll, that.left.right)
              Chunk.Concat(nl, that.right)
            } else {
              val nr = Chunk.Concat(that.left.right, that.right)
              Chunk.Concat(nll, nr)
            }
          }
        }
    }

  /**
   * Returns the concatenation of this chunk with the specified non-empty chunk.
   */
  final def ++[A1 >: A](that: NonEmptyChunk[A1]): NonEmptyChunk[A1] =
    that.prepend(self)

  /**
   * Returns the bitwise AND of this chunk and the specified chunk.
   */
  def &(that: Chunk[Boolean])(implicit ev: A <:< Boolean): Chunk.BitChunkByte =
    Chunk.bitwise(self.asInstanceOf[Chunk[Boolean]], that, _ & _)

  /**
   * Returns the bitwise OR of this chunk and the specified chunk.
   */
  def |(that: Chunk[Boolean])(implicit ev: A <:< Boolean): Chunk.BitChunkByte =
    Chunk.bitwise(self.asInstanceOf[Chunk[Boolean]], that, _ | _)

  /**
   * Returns the bitwise XOR of this chunk and the specified chunk.
   */
  def ^(that: Chunk[Boolean])(implicit ev: A <:< Boolean): Chunk.BitChunkByte =
    Chunk.bitwise(self.asInstanceOf[Chunk[Boolean]], that, _ ^ _)

  /**
   * Returns the bitwise NOT of this chunk.
   */
  def negate(implicit ev: A <:< Boolean): Chunk.BitChunkByte = {
    val bits      = self.length
    val fullBytes = bits >> 3
    val remBytes  = bits & 7
    val arr       = Array.ofDim[Byte](fullBytes + (if (remBytes == 0) 0 else 1))
    var i         = 0
    var mask      = 128
    while (i < fullBytes) {
      var byte = 0
      mask = 128
      (0 until 8).foreach { k =>
        byte = byte | (if (!ev(self(i * 8 + k))) mask else 0)
        mask >>= 1
      }
      arr(i) = byte.asInstanceOf[Byte]
      i += 1
    }
    if (remBytes != 0) {
      var byte = 0
      mask = 128
      (0 until remBytes).foreach { k =>
        byte = byte | (if (!ev(self(fullBytes * 8 + k))) mask else 0)
        mask >>= 1
      }
      arr(fullBytes) = byte.asInstanceOf[Byte]
    }
    Chunk.BitChunkByte(Chunk.fromArray(arr), 0, bits)
  }

  /**
   * Creates a base64 encoded string based on the chunk's data.
   */
  def asBase64String(implicit ev: Chunk.IsText[A]): String = {
    val encoder = java.util.Base64.getEncoder
    ev match {
      case Chunk.IsText.byteIsText =>
        encoder.encodeToString(self.asInstanceOf[Chunk[Byte]].toArray)
      case Chunk.IsText.charIsText =>
        encoder.encodeToString(self.asInstanceOf[Chunk[Char]].toArray.map(_.toByte))
      case Chunk.IsText.strIsText =>
        encoder.encodeToString(ev.convert(self).getBytes)
    }
  }

  /**
   * Converts a chunk of ints to a chunk of bits.
   */
  final def asBitsInt(endianness: Chunk.BitChunk.Endianness)(implicit ev: A <:< Int): Chunk[Boolean] =
    if (self.isEmpty) Chunk.empty
    else Chunk.BitChunkInt(self.asInstanceOf[Chunk[Int]], endianness, 0, length << 5)

  /**
   * Converts a chunk of longs to a chunk of bits.
   */
  final def asBitsLong(endianness: Chunk.BitChunk.Endianness)(implicit ev: A <:< Long): Chunk[Boolean] =
    if (self.isEmpty) Chunk.empty
    else Chunk.BitChunkLong(self.asInstanceOf[Chunk[Long]], endianness, 0, length << 6)

  /**
   * Converts a chunk of bytes to a chunk of bits.
   */
  final def asBitsByte(implicit ev: A <:< Byte): Chunk[Boolean] =
    if (self.isEmpty) Chunk.empty
    else Chunk.BitChunkByte(self.map(ev), 0, length << 3)

  def toPackedByte(implicit ev: A <:< Boolean): Chunk[Byte] =
    if (self.isEmpty) Chunk.empty
    else Chunk.ChunkPackedBoolean[Byte](self.asInstanceOf[Chunk[Boolean]], 8, Chunk.BitChunk.Endianness.BigEndian)
  def toPackedInt(endianness: Chunk.BitChunk.Endianness)(implicit ev: A <:< Boolean): Chunk[Int] =
    if (self.isEmpty) Chunk.empty
    else Chunk.ChunkPackedBoolean[Int](self.asInstanceOf[Chunk[Boolean]], 32, endianness)
  def toPackedLong(endianness: Chunk.BitChunk.Endianness)(implicit ev: A <:< Boolean): Chunk[Long] =
    if (self.isEmpty) Chunk.empty
    else Chunk.ChunkPackedBoolean[Long](self.asInstanceOf[Chunk[Boolean]], 64, endianness)

  /**
   * Creates a new String based on this chunks data.
   */
  final def asString(implicit ev: Chunk.IsText[A]): String = ev.convert(self)

  /**
   * Creates a new String based on this chunk of bytes and using the given
   * charset.
   */
  final def asString(charset: Charset)(implicit ev: A <:< Byte): String = {
    new String(self.toArray.asInstanceOf[Array[Byte]], charset)
  }

  /**
   * Get the element at the specified index.
   */
  def boolean(index: Int)(implicit ev: A <:< Boolean): Boolean =
    ev(apply(index))

  /**
   * Get the element at the specified index.
   */
  def byte(index: Int)(implicit ev: A <:< Byte): Byte =
    ev(apply(index))

  /**
   * Get the element at the specified index.
   */
  def char(index: Int)(implicit ev: A <:< Char): Char =
    ev(apply(index))

  /**
   * Transforms all elements of the chunk for as long as the specified partial
   * function is defined.
   */
  def collectWhile[B](pf: PartialFunction[A, B]): Chunk[B] =
    if (isEmpty) Chunk.empty else self.materialize.collectWhile(pf)

  /**
   * Determines whether this chunk and the specified chunk have the same length
   * and every pair of corresponding elements of this chunk and the specified
   * chunk satisfy the specified predicate.
   */
  final def corresponds[B](that: Chunk[B])(f: (A, B) => Boolean): Boolean =
    if (self.length != that.length) false
    else {
      val leftIterator  = self.chunkIterator
      val rightIterator = that.chunkIterator
      var index         = 0
      var equal         = true
      while (equal && leftIterator.hasNextAt(index) && rightIterator.hasNextAt(index)) {
        val a = leftIterator.nextAt(index)
        val b = rightIterator.nextAt(index)
        index += 1
        equal = f(a, b)
      }
      equal
    }

  /**
   * Deduplicates adjacent elements that are identical.
   */
  def dedupe: Chunk[A] = {
    val builder = ChunkBuilder.make[A]()

    var lastA = null.asInstanceOf[A]

    foreach { a =>
      if (a != lastA) builder += a

      lastA = a
    }

    builder.result()
  }

  /**
   * Get the element at the specified index.
   */
  def double(index: Int)(implicit ev: A <:< Double): Double =
    ev(apply(index))

  /**
   * Drops the first `n` elements of the chunk.
   */
  def drop(n: Int): Chunk[A] = {
    val len = self.length

    if (n <= 0) self
    else if (n >= len) Chunk.empty
    else
      self match {
        case Chunk.Slice(c, o, l) => Chunk.Slice(c, o + n, l - n)
        case Chunk.Concat(l, r) =>
          if (n > l.length) r.drop(n - l.length)
          else Chunk.Concat(l.drop(n), r)
        case _ =>
          if (depth >= MaxDepthBeforeMaterialize) Chunk.Slice(self.materialize, n, len - n)
          else Chunk.Slice(self, n, len - n)
      }
  }

  /**
   * Drops the last `n` elements of the chunk.
   */
  def dropRight(n: Int): Chunk[A] = {
    val len = self.length

    if (n <= 0) self
    else if (n >= len) Chunk.empty
    else
      self match {
        case Chunk.Slice(c, o, l) => Chunk.Slice(c, o, l - n)
        case Chunk.Concat(l, r) =>
          if (n > r.length) l.dropRight(n - r.length)
          else Chunk.Concat(l, r.dropRight(n))
        case _ =>
          if (depth >= MaxDepthBeforeMaterialize) Chunk.Slice(self.materialize, 0, len - n)
          else Chunk.Slice(self, 0, len - n)
      }
  }

  // Additional pure methods ported from ZIO (foldLeft, map, filter, etc.)
  def foldLeft[@specialized S](s0: S)(f: (S, A) => S): S = {
    val len = self.length
    var s = s0
    var i = 0
    while (i < len) {
      s = f(s, self(i))
      i += 1
    }
    s
  }

  def map[B](f: A => B): Chunk[B] = materialize.map(f)

  def filter(p: A => Boolean): Chunk[A] = materialize.filter(p)

  def flatMap[B](f: A => Chunk[B]): Chunk[B] = materialize.flatMap(f)

  def materialize: Chunk[A] = {
    val len = length
    val arr = Array.ofDim[Any](len)
    var i = 0
    while (i < len) {
      arr(i) = apply(i)
      i += 1
    }
    Chunk.fromArray(arr).asInstanceOf[Chunk[A]]
  }

  def take(n: Int): Chunk[A] = if (n <= 0) Chunk.empty else if (n >= length) self else Slice(self, 0, n)

  def takeRight(n: Int): Chunk[A] = if (n <= 0) Chunk.empty else if (n >= length) self else Slice(self, length - n, n)

  def forall(p: A => Boolean): Boolean = foldLeft(true)((b, a) => b && p(a))

  def exists(p: A => Boolean): Boolean = !forall(!p(_))

  def find(p: A => Boolean): Option[A] = {
    val len = length
    var i = 0
    while (i < len) {
      val a = apply(i)
      if (p(a)) return Some(a)
      i += 1
    }
    None
  }

  def foreach[U](f: A => U): Unit = {
    val len = length
    var i = 0
    while (i < len) {
      f(apply(i))
      i += 1
    }
  }

  def toArray[B >: A: ClassTag]: Array[B] = {
    val dest = Array.ofDim[B](length)
    copyToArray(0, dest, 0, length)
    dest
  }

  def copyToArray[B >: A](from: Int, dest: Array[B], destPos: Int, length: Int): Unit = {
    var i = 0
    val end = from + length
    var j = destPos
    while (i < end - from) {
      dest(j) = apply(from + i).asInstanceOf[B]
      i += 1
      j += 1
    }
  }

  override def equals(that: Any): Boolean = that match {
    case that: Chunk[_] => corresponds(that.asInstanceOf[Chunk[A]])( _ == _ )
    case _ => false
  }

  override def hashCode(): Int = {
    var h = MurmurHash3.arraySeed
    val len = length
    var i = 0
    while (i < len) {
      h = MurmurHash3.mix(h, apply(i).##)
      i += 1
    }
    MurmurHash3.finalizeHash(h, len)
  }

  // Depth for balanced concat
  def depth: Int = self match {
    case Concat(_, _) => 1 + (self.left.depth max self.right.depth)
    case _ => 0
  }

  def concatDepth: Int = depth + 1

  def left: Chunk[A] = self match {
    case Concat(l, _) => l
    case _ => self
  }

  def right: Chunk[A] = self match {
    case Concat(_, r) => r
    case _ => self
  }
}

object Chunk {
  private val MaxDepthBeforeMaterialize = 10

  def empty[A]: Chunk[A] = Empty

  def fromArray[A](arr: Array[A]): Chunk[A] = if (arr.isEmpty) Empty else ArrayChunk(arr)

  def fromIterable[A](it: Iterable[A]): Chunk[A] = {
    it match {
      case chunk: Chunk[A] => chunk
      case seq: IndexedSeq[A] => fromIndexedSeq(seq)
      case linear: LinearSeq[A] => fromLinearSeq(linear)
      case _ => fromIterator(it.iterator)
    }
  }

  private def fromIndexedSeq[A](seq: IndexedSeq[A]): Chunk[A] = {
    if (seq.isEmpty) Empty
    else if (seq.lengthCompare(Chunk.BufferSize) <= 0) ArrayChunk(seq.toArray)
    else {
      val (left, right) = seq.splitAt(seq.length / 2)
      Concat(fromIndexedSeq(left), fromIndexedSeq(right))
    }
  }

  private def fromLinearSeq[A](seq: LinearSeq[A]): Chunk[A] = {
    if (seq.isEmpty) Empty
    else {
      val builder = ChunkBuilder.make[A]()
      var current = seq
      while (current.nonEmpty) {
        builder += current.head
        current = current.tail
      }
      builder.result()
    }
  }

  def fromIterator[A](it: Iterator[A]): Chunk[A] = {
    val builder = ChunkBuilder.make[A]()
    it.foreach(builder += _)
    builder.result()
  }

  // Bitwise operations
  def bitwise(left: Chunk[Boolean], right: Chunk[Boolean], f: (Boolean, Boolean) => Boolean): BitChunkByte = {
    val length = left.length min right.length
    val arr = Array.ofDim[Byte](length / 8 + (if (length % 8 == 0) 0 else 1))
    var i = 0
    var byteIndex = 0
    var bitIndex = 0
    var byte = 0
    while (i < length) {
      val bit = f(left(i), right(i))
      if (bit) byte |= (1 << (7 - bitIndex))
      bitIndex += 1
      if (bitIndex == 8) {
        arr(byteIndex) = byte.toByte
        byteIndex += 1
        bitIndex = 0
        byte = 0
      }
      i += 1
    }
    if (bitIndex > 0) arr(byteIndex) = byte.toByte
    BitChunkByte(fromArray(arr), 0, length)
  }

  sealed trait BitChunkEnd {
    def length: Int
    def apply(index: Int): Boolean
  }

  object BitChunk {
    sealed trait Endianness
    case object BigEndian extends Endianness
    case object LittleEndian extends Endianness
  }

  case class BitChunkByte(chunk: Chunk[Byte], byteOffset: Int, bitLength: Int) extends Chunk[Boolean] with BitChunkEnd {
    def length: Int = bitLength

    def apply(index: Int): Boolean = {
      val byteIndex = byteOffset + (index / 8)
      val bitIndex = 7 - (index % 8)
      (chunk(byteIndex) & (1 << bitIndex)) != 0
    }

    def chunkIterator: ChunkIterator[Boolean] = new ChunkIterator.BitIterator(this)
  }

  case class BitChunkInt(chunk: Chunk[Int], endianness: BitChunk.Endianness, intOffset: Int, bitLength: Int) extends Chunk[Boolean] with BitChunkEnd {
    def length: Int = bitLength

    def apply(index: Int): Boolean = {
      val intIndex = intOffset + (index / 32)
      val bitIndex = endianness match {
        case BitChunk.BigEndian => 31 - (index % 32)
        case BitChunk.LittleEndian => index % 32
      }
      (chunk(intIndex) & (1 << bitIndex)) != 0
    }

    def chunkIterator: ChunkIterator[Boolean] = new ChunkIterator.BitIterator(this)
  }

  case class BitChunkLong(chunk: Chunk[Long], endianness: BitChunk.Endianness, longOffset: Int, bitLength: Int) extends Chunk[Boolean] with BitChunkEnd {
    def length: Int = bitLength

    def apply(index: Int): Boolean = {
      val longIndex = longOffset + (index / 64)
      val bitIndex = endianness match {
        case BitChunk.BigEndian => 63 - (index % 64)
        case BitChunk.LittleEndian => index % 64
      }
      (chunk(longIndex) & (1L << bitIndex)) != 0
    }

    def chunkIterator: ChunkIterator[Boolean] = new ChunkIterator.BitIterator(this)
  }

  // Packed Boolean
  case class ChunkPackedBoolean[B](bits: Chunk[Boolean], bitsPerElement: Int, endianness: BitChunk.Endianness)(implicit ev: Numeric[B]) extends Chunk[B] {
    def length: Int = bits.length / bitsPerElement

    def apply(index: Int): B = {
      var value = ev.zero
      val startBit = index * bitsPerElement
      var i = 0
      while (i < bitsPerElement) {
        if (bits(startBit + i)) {
          val shift = endianness match {
            case BitChunk.BigEndian => bitsPerElement - 1 - i
            case BitChunk.LittleEndian => i
          }
          value = ev.plus(value, ev.fromInt(1 << shift))
        }
        i += 1
      }
      value
    }

    def chunkIterator: ChunkIterator[B] = new ChunkIterator.PackedIterator[B](this)
  }

  // Other cases
  private case object Empty extends Chunk[Nothing] {
    def length: Int = 0

    def apply(index: Int): Nothing = throw new IndexOutOfBoundsException(s"Empty chunk doesn't allow indexing at $index")

    def chunkIterator: ChunkIterator[Nothing] = ChunkIterator.empty

    override def toString: String = "Chunk()"
  }

  final case class Singleton[A](a: A) extends Chunk[A] {
    def length: Int = 1

    def apply(index: Int): A = if (index == 0) a else throw new IndexOutOfBoundsException(s"Singleton chunk doesn't allow indexing at $index")

    def chunkIterator: ChunkIterator[A] = ChunkIterator.singleton(a)
  }

  final case class ArrayChunk[A](arr: Array[A]) extends Chunk[A] {
    def length: Int = arr.length

    def apply(index: Int): A = if (0 <= index && index < length) arr(index) else throw new IndexOutOfBoundsException(s"Array chunk doesn't allow indexing at $index")

    def chunkIterator: ChunkIterator[A] = ChunkIterator.fromArray(arr)
  }

  final case class Concat[+A](left: Chunk[A], right: Chunk[A]) extends Chunk[A] {
    def length: Int = left.length + right.length

    def apply(index: Int): A = if (index < left.length) left(index) else right(index - left.length)

    def chunkIterator: ChunkIterator[A] = ChunkIterator.concat(left.chunkIterator, right.chunkIterator)
  }

  final case class Slice[A](chunk: Chunk[A], offset: Int, length: Int) extends Chunk[A] {
    def apply(index: Int): A = chunk(offset + index)

    def chunkIterator: ChunkIterator[A] = ChunkIterator.slice(chunk.chunkIterator, offset, length)
  }

  private final case class AppendN[A](start: Chunk[A], buffer: Array[AnyRef], bufferUsed: Int, chain: AtomicInteger) extends Chunk[A] {
    // Implementation for buffered append (optimized for repeated ++)
    // (Omitted for brevity; ported from ZIO with atomic for thread-safety, but since pure, can be non-atomic if single-threaded)
    def length: Int = start.length + bufferUsed

    def apply(index: Int): A = if (index < start.length) start(index) else buffer(index - start.length).asInstanceOf[A]

    def chunkIterator: ChunkIterator[A] = // implement accordingly
      ???
  }

  private final case class PrependN[A](end: Chunk[A], buffer: Array[AnyRef], bufferUsed: Int, chain: AtomicInteger) extends Chunk[A] {
    // Similar to AppendN
    def length: Int = end.length + bufferUsed

    def apply(index: Int): A = if (index < bufferUsed) buffer(index).asInstanceOf[A] else end(index - bufferUsed)

    def chunkIterator: ChunkIterator[A] = // implement
      ???
  }

  // ChunkIterator trait and implementations
  trait ChunkIterator[+A] extends Iterator[A] {
    def hasNextAt(index: Int): Boolean
    def nextAt(index: Int): A

    override def hasNext: Boolean = hasNextAt(0)
    override def next(): A = {
      val a = nextAt(0)
      drop(1)
      a
    }

    def drop(n: Int): Unit = // implement if needed
    ()

    // BitIterator, etc.
  }

  object ChunkIterator {
    def empty[A]: ChunkIterator[A] = new ChunkIterator[A] {
      def hasNextAt(index: Int): Boolean = false
      def nextAt(index: Int): A = throw new NoSuchElementException("Empty iterator")
    }

    def singleton[A](a: A): ChunkIterator[A] = new ChunkIterator[A] {
      private var consumed = false
      def hasNextAt(index: Int): Boolean = index == 0 && !consumed
      def nextAt(index: Int): A = if (index == 0 && !consumed) { consumed = true; a } else throw new NoSuchElementException
    }

    def fromArray[A](arr: Array[A]): ChunkIterator[A] = new ChunkIterator[A] {
      private var pos = 0
      def hasNextAt(index: Int): Boolean = index < arr.length
      def nextAt(index: Int): A = arr(index)
    }

    def concat[A](left: ChunkIterator[A], right: ChunkIterator[A]): ChunkIterator[A] = new ChunkIterator[A] {
      private var leftConsumed = false
      private var currentLeftIndex = 0
      private var currentRightIndex = 0
      def hasNextAt(index: Int): Boolean = {
        if (index < left.length) left.hasNextAt(currentLeftIndex)
        else right.hasNextAt(currentRightIndex)
      }
      def nextAt(index: Int): A = {
        if (index < left.length) {
          val a = left.nextAt(currentLeftIndex)
          currentLeftIndex += 1
          a
        } else {
          val a = right.nextAt(currentRightIndex)
          currentRightIndex += 1
          a
        }
      }
    }

    // Add slice, bit, packed as needed
  }

  // Builder
  class ChunkBuilder[A] private (private var chunks: List[Chunk[A]] = Nil, private var size: Int = 0) {
    def this() = this(Nil, 0)

    def +=(a: A): this.type = {
      val singleton = Singleton(a)
      chunks ::= singleton
      size += 1
      this
    }

    def ++=(that: Chunk[A]): this.type = {
      chunks ::= that
      size += that.length
      this
    }

    def result(): Chunk[A] = {
      chunks match {
        case Nil => Empty
        case head :: Nil => head
        case _ => fromChunks(chunks.reverse)
      }
    }

    private def fromChunks(cs: List[Chunk[A]]): Chunk[A] = {
      cs match {
        case Nil => Empty
        case head :: Nil => head
        case left :: right :: tail =>
          val concat = Concat(left, right)
          fromChunks(concat :: tail)
      }
    }
  }

  object ChunkBuilder {
    def make[A]: ChunkBuilder[A] = new ChunkBuilder[A]
  }

  // IsText for asString
  sealed trait IsText[A] {
    def convert(chunk: Chunk[A]): String
  }

  object IsText {
    implicit val byteIsText: IsText[Byte] = new IsText[Byte] {
      def convert(chunk: Chunk[Byte]): String = new String(chunk.toArray)
    }

    implicit val charIsText: IsText[Char] = new IsText[Char] {
      def convert(chunk: Chunk[Char]): String = new String(chunk.toArray)
    }

    implicit val strIsText: IsText[String] = new IsText[String] {
      def convert(chunk: Chunk[String]): String = chunk.mkString
    }
  }
}

// NonEmptyChunk for optimized ops
sealed trait NonEmptyChunk[+A] extends Chunk[A] {
  def prepend[B >: A](that: Chunk[B]): NonEmptyChunk[B]
}

// Implement as extension or subclass if needed
