src/test/scala/zio/blocks/chunk/ChunkSpec.scala
Scalapackage zio.blocks.chunk

import org.scalatest.funsuite.AnyFunSuite
import org.scalatest.matchers.should.Matchers

class ChunkSpec extends AnyFunSuite with Matchers {

  test("basic construction and access") {
    val chunk = Chunk(1, 2, 3)
    chunk.length shouldBe 3
    chunk(0) shouldBe 1
    chunk(1) shouldBe 2
    chunk(2) shouldBe 3
    a [IndexOutOfBoundsException] should be thrownBy chunk(3)
  }

  test("concatenation") {
    val left = Chunk(1, 2)
    val right = Chunk(3, 4)
    val concat = left ++ right
    concat.toArray shouldBe Array(1, 2, 3, 4)
    concat.length shouldBe 4
  }

  test("drop and take") {
    val chunk = Chunk(1, 2, 3, 4, 5)
    chunk.drop(2).toArray shouldBe Array(3, 4, 5)
    chunk.take(3).toArray shouldBe Array(1, 2, 3)
    chunk.dropRight(2).toArray shouldBe Array(1, 2, 3)
    chunk.takeRight(2).toArray shouldBe Array(4, 5)
  }

  test("map and filter") {
    val chunk = Chunk(1, 2, 3, 4)
    chunk.map(_ * 2).toArray shouldBe Array(2, 4, 6, 8)
    chunk.filter(_ % 2 == 0).toArray shouldBe Array(2, 4)
  }

  test("foldLeft") {
    val chunk = Chunk(1, 2, 3)
    chunk.foldLeft(0)(_ + _) shouldBe 6
  }

  test("bitwise operations") {
    val left = Chunk(true, false, true, true)
    val right = Chunk(false, true, true, false)
    (left & right).toArray shouldBe Array(false, false, true, false)
    (left | right).toArray shouldBe Array(true, true, true, true)
    (left ^ right).toArray shouldBe Array(true, true, false, true)
  }

  test("fromIterable") {
    val list = List(1, 2, 3)
    Chunk.fromIterable(list).toArray shouldBe Array(1, 2, 3)
  }

  // Port more tests from ZIO's original suite (e.g., dedupe, collectWhile, corresponds, etc.)
  test("dedupe") {
    val chunk = Chunk(1, 1, 2, 2, 3)
    chunk.dedupe.toArray shouldBe Array(1, 2, 3)
  }

  test("collectWhile") {
    val chunk = Chunk(1, 2, 3, 0, 4)
    chunk.collectWhile { case x if x > 0 => x }.toArray shouldBe Array(1, 2, 3)
  }

  test("corresponds") {
    val left = Chunk(1, 2, 3)
    val right = Chunk(2, 4, 6)
    left.corresponds(right)(_ * 2 == _ ) shouldBe true
  }

  // Add ~200 more tests ported from ZIO ChunkSpec, covering edge cases, primitives, large concats, etc.
}
