I have an ad-hoc deriver for named tuples for ZIO Schema 1 like the following:

```scala
  inline given derivedNamedTuple: [T <: NamedTuple.AnyNamedTuple] => (mirror: scala.deriving.Mirror.ProductOf[T]) => Schema[T] = {
    import scala.compiletime.{constValueTuple, erasedValue, summonInline}

    // Extract field names from Mirror's MirroredElemLabels
    val fieldNames = constValueTuple[mirror.MirroredElemLabels].toList.asInstanceOf[List[String]]

    // Summon all field schemas recursively
    val fieldSchemas = summonFieldSchemas[mirror.MirroredElemTypes]

    // Create Record fields using ZIO Schema Field
    val recordFields = fieldNames.zip(fieldSchemas).map { case (name, schema) =>
      Schema.Field(
        name0 = name,
        schema0 = schema,
        annotations0 = zio.Chunk.empty,
        validation0 = zio.schema.validation.Validation.succeed,
        get0 = (record: scala.collection.immutable.ListMap[String, Any]) => record(name),
        set0 = (record: scala.collection.immutable.ListMap[String, Any], value: Any) => record + (name -> value)
      )
    }

    // Create FieldSet from fields
    val fieldSet = FieldSet(recordFields*)

    // Create ZIO Schema Record using FieldSet with descriptive TypeId
    val typeIdString = s"NamedTuple(${fieldNames.mkString(",")})"
    val recordSchema = Schema.record(
      id = TypeId.parse(typeIdString),
      fieldSet = fieldSet
    )

    // Transform the record schema to work with tuples
    val recordToTuple = (record: scala.collection.immutable.ListMap[String, Any]) => {
      val values = fieldNames.map(record(_))
      mirror.fromProduct(Tuple.fromArray(values.toArray))
    }

    val tupleToRecord = (tuple: T) => {
      val values = (0 until tuple.asInstanceOf[Product].productArity).map(tuple.asInstanceOf[Product].productElement)
      fieldNames.zip(values).to(scala.collection.immutable.ListMap)
    }

    recordSchema.transform(recordToTuple, tupleToRecord)
  }

  // Helper to recursively summon schemas for all tuple elements
  @SuppressWarnings(Array("org.wartremover.warts.AsInstanceOf"))
  private inline def summonFieldSchemas[Elems <: Tuple]: List[Schema[Any]] = {
    import scala.compiletime.{erasedValue, summonInline}

    inline erasedValue[Elems] match {
      case _: (head *: tail) =>
        summonInline[Schema[head]].zioSchema.asInstanceOf[Schema[Any]] :: summonFieldSchemas[tail]
      case _: EmptyTuple =>
        Nil
    }
  }
```

